import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export class NameIconEquippedParser implements IMessageParser
{
    private _userId: number = 0;
    private _iconId: number = 0;
    private _iconKey: string = '';

    public flush(): boolean
    {
        this._userId = 0;
        this._iconId = 0;
        this._iconKey = '';
        return true;
    }

    public parse(wrapper: IMessageDataWrapper): boolean
    {
        if(!wrapper) return false;

        this._userId = wrapper.readInt();
        this._iconId = wrapper.readInt();
        this._iconKey = wrapper.readString();

        return true;
    }

    public get userId(): number
    {
        return this._userId;
    }

    public get iconId(): number
    {
        return this._iconId;
    }

    public get iconKey(): string
    {
        return this._iconKey;
    }
}
